75: 
76:     logic [$bits(dmi_t)-1:0] dr_d, dr_q;
77:     logic [6:0] address_d, address_q;
78:     logic [31:0] data_d, data_q, pass;
79:     logic pass_chk;
80: 
81:     dmi_t  dmi;
82:     assign dmi          = dmi_t'(dr_q);
83:     assign dmi_req.addr = address_q;
84:     assign dmi_req.data = data_q;
85:     assign dmi_req.op   = (state_q == Write) ? dm::DTM_WRITE : dm::DTM_READ;
86:     // we'will always be ready to accept the data we requested
87:     assign dmi_resp_ready = 1'b1;
88:     //assign pass = 32'hDEADC0DE;
89: 
90:     logic error_dmi_busy;
91:     dmi_error_t error_d, error_q;
92: 
93:     always_comb begin
94:         error_dmi_busy = 1'b0;
95:         // default assignments
96:         state_d   = state_q;
97:         address_d = address_q;
98:         data_d    = data_q;
99:         error_d   = error_q;
100: 
101:         dmi_req_valid = 1'b0;
102: 
103:         case (state_q)
104:             Idle: begin
105:                 // make sure that no error is sticky
106:                 if (dmi_access && update_dr && (error_q == DMINoError)) begin
107:                     // save address and value
108:                     address_d = dmi.address;
109:                     data_d = dmi.data;
110:                     if ((dm::dtm_op_t'(dmi.op) == dm::DTM_READ) && (pass_chk == 1'b1)) begin
111:                         state_d = Read;
112:                     end else if ((dm::dtm_op_t'(dmi.op) == dm::DTM_WRITE)) begin
113:                         state_d = Write;
114:                     end else if (dm::dtm_op_t'(dmi.op) == dm::DTM_PASS) begin
115: 			state_d = Read; //reads input password
116: 			if (data_d == pass) begin //checks password
117: 			    pass_chk = 1'b1;	
118: 			end
119: 			state_d = Idle;
120: 		    end
121:                     // else this is a nop and we can stay here
122:                 end
123:             end
124: 
125:             Read: begin
126:                 dmi_req_valid = 1'b1;
127:                 if (dmi_req_ready) begin
128:                     state_d = WaitReadValid;
129:                 end
130:             end
131: 
132:             WaitReadValid: begin
133:                 // load data into register and shift out
134:                 if (dmi_resp_valid) begin
135:                     data_d = dmi_resp.data;
136:                     state_d = Idle;
137:                 end
138:             end
139: 
140:             Write: begin
141:                 dmi_req_valid = 1'b1;
142:                 // got a valid answer go back to idle
143:                 if (dmi_req_ready) begin
144:                     state_d = Idle;
145:                 end
146:             end
147: 
148:             WaitWriteValid: begin
149:                 // just wait for idle here
150:                 if (dmi_resp_valid) begin
151:                     state_d = Idle;
152:                 end
153:             end
154:         endcase
155: 
156:         // update_dr means we got another request but we didn't finish
157:         // the one in progress, this state is sticky
158:         if (update_dr && state_q != Idle) begin
159:             error_dmi_busy = 1'b1;
160:         end
161: 
162:         // if capture_dr goes high while we are in the read state
163:         // or in the corresponding wait state we are not giving back a valid word
164:         // -> throw an error
165:         if (capture_dr && state_q inside {Read, WaitReadValid}) begin
166:             error_dmi_busy = 1'b1;
167:         end
168: 
169:         if (error_dmi_busy) begin
170:             error_d = DMIBusy;
171:         end
172:         // clear sticky error flag
173:         if (dmi_reset && dtmcs_select) begin
174:             error_d = DMINoError;
175:         end
